ENTRY.N_AMT:
var ex=DV.getCurrentDoData('CHG_COMM_DESC');
 var amt='0';

 if(ex != null && ex.equals('Receiving Bank Charges')){
    amt=DV.getCurrentDoData('CHG_PAY_AMT');;
 }
 DV.appendField(amt);

ENTRY.C_INTEREST_RATE1:
var ccy1 = DV.getFieldValue("CHG_FLD_LOCAL_CUST_CCY");
  var ccy2 = 'ZMK';
  var baseCCY = 'ZMK';
  var rate = '123456789';
  var defaultRate = '1';
  var cnty = DV.getCountryCode();
  if(ccy1 != 'ZMK'){
    DV.writeLog("coming 73");
    sql = "C_FROM_CCY = '"+ ccy1 +"' AND C_TO_CCY='ZMK' and C_BK_GROUP_ID='STBANK' and C_CNTY_CODE='"+cnty+"' and C_DESC_ID='Booking Rate' ";
    DV.SYS_getTableData('F_VALUE','EXIMSYS.STD_EXCHAN_RATE',sql);
  }else{
    DV.writeLog("coming 74");
    DV.appendField(defaultRate);
  }

ENTRY.C_REF_NUMBER:
var type;
  var cash=DV.getFieldValue('CHG_CASH_IND');
   if (cash.equals('Yes')){
     type ='BANK';
   }else{
     type ='CUSTOMER';
   }
   DV.appendField(type);

ENTRY.C_VCH_SPECIAL1:
var dest=DV.getFieldValue("CHG_FLD_ALL_CHARGE_FOR");
  if(dest != null && dest.equals('F')){
    DV.appendField('');
  }else{
    var cash=DV.getFieldValue('CHG_CASH_IND');
    if (cash.equals('No')){
      var acc=DV.getFieldValue('CHG_FLD_LOCAL_CUST_AC_NO');
      var sql="C_AC_NUMBER='" + acc + "'";
      DV.SYS_getTableData('C_AC_TITLE','eximsys.std_ac_number',sql);
    }else{
      var title ='SETTLEMENT SUSPENSE';
      DV.appendField(title);
    }
  }
